arguments.command:
$ErrorActionPreference='Stop'
$base='https://services.leadconnectorhq.com'
$loc='TW8JsPW5NMnA3tfK2XLn'
$owner='02W3bSai20o2qBucnTUf'
$pipeline='WwwiXO65toZOTQptzmWp'
$newLeadStage='0f0bf7d5-641b-44f2-9bb8-73d838b09122'
$token=$env:GHL_PRIVATE_INTEGRATION_TOKEN
$h=@{Authorization="Bearer $token"; Version='2021-07-28'; Accept='application/json'; 'Content-Type'='application/json'}

$contacts=(Invoke-RestMethod -Method Get -Uri "$base/contacts/?locationId=$loc&limit=100" -Headers $h).contacts
$opps=(Invoke-RestMethod -Method Post -Uri "$base/opportunities/search" -Headers $h -Body (@{locationId=$loc;limit=100}|ConvertTo-Json)).opportunities
$oppByContact=@{}
foreach($o in $opps){$oppByContact[$o.contactId]=$o}

$now=Get-Date
$recent=$contacts | Where-Object { [datetime]$_.dateAdded -gt $now.ToUniversalTime().AddHours(-24) -and ($_.source -match 'Scorecard|survey|Divine Alignment') }
$createdOpp=0;$updatedOpp=0;$tasks=0;$tagged=0
$breaches=@()
foreach($c in $recent){
  $cid=$c.id
  $added=[datetime]$c.dateAdded
  $mins=($now.ToUniversalTime()-$added).TotalMinutes
  if(-not $oppByContact.ContainsKey($cid)){
    $name=(if($c.contactName){$c.contactName}else{'Unknown'}) + ' - New Lead'
    $body=@{locationId=$loc;contactId=$cid;name=$name;pipelineId=$pipeline;pipelineStageId=$newLeadStage;status='open';assignedTo=$owner}|ConvertTo-Json
    try{Invoke-RestMethod -Method Post -Uri "$base/opportunities/" -Headers $h -Body $body|Out-Null;$createdOpp++}catch{}
  } else {
    $opp=$oppByContact[$cid]
    if(-not $opp.assignedTo){
      $ub=@{assignedTo=$owner}|ConvertTo-Json
      try{Invoke-RestMethod -Method Put -Uri "$base/opportunities/$($opp.id)" -Headers $h -Body $ub|Out-Null;$updatedOpp++}catch{}
    }
  }

  # Ensure contact owner
  if(-not $c.assignedTo){
    try{Invoke-RestMethod -Method Put -Uri "$base/contacts/$cid" -Headers $h -Body (@{locationId=$loc;assignedTo=$owner}|ConvertTo-Json)|Out-Null}catch{}
  }

  # SLA breach task for >10m
  if($mins -gt 10){
    $taskBody=@{title='URGENT: First follow-up due (>10m waiting)';dueDate=$now.ToUniversalTime().AddMinutes(10).ToString('o');completed=$false}|ConvertTo-Json
    try{Invoke-RestMethod -Method Post -Uri "$base/contacts/$cid/tasks" -Headers $h -Body $taskBody|Out-Null;$tasks++}catch{}
    $breaches += [pscustomobject]@{contactId=$cid;name=$c.contactName;waitMins=[math]::Round($mins,0);channel=((if($c.phone){'sms'}elseif($c.email){'email'}else{'none'}))}
    # add tags as next-action markers
    try{Invoke-RestMethod -Method Post -Uri "$base/contacts/$cid/tags" -Headers $h -Body (@{tags=@('l2-inbound-waiting-10m','l2-task-inbound-created','needs-followup-24h')}|ConvertTo-Json)|Out-Null;$tagged++}catch{}
  }
}

$result=[pscustomobject]@{recentCount=$recent.Count;createdOpp=$createdOpp;updatedOpp=$updatedOpp;tasksCreated=$tasks;tagsApplied=$tagged;breaches=$breaches}
$result|ConvertTo-Json -Depth 6

